import requests
import json

# RabbitMQ Management API credentials
RABBITMQ_API_URL = 'http://localhost:15672/api'
USERNAME = 'guest'
PASSWORD = 'guest'

# Function to create a virtual host
def create_vhost(vhost):
    url = f"{RABBITMQ_API_URL}/vhosts/{vhost}"
    response = requests.put(url, auth=(USERNAME, PASSWORD))
    if response.status_code == 201:
        print(f"Virtual host '{vhost}' created.")
    else:
        print(f"Failed to create virtual host '{vhost}': {response.content}")

# Function to create a user
def create_user(username, password):
    url = f"{RABBITMQ_API_URL}/users/{username}"
    data = {
        "password": password,
        "tags": ""
    }
    response = requests.put(url, auth=(USERNAME, PASSWORD), json=data)
    if response.status_code == 201:
        print(f"User '{username}' created.")
    else:
        print(f"Failed to create user '{username}': {response.content}")

# Function to set permissions for a user on a virtual host
def set_permissions(username, vhost):
    url = f"{RABBITMQ_API_URL}/permissions/{vhost}/{username}"
    data = {
        "configure": ".*",
        "write": ".*",
        "read": ".*"
    }
    response = requests.put(url, auth=(USERNAME, PASSWORD), json=data)
    if response.status_code == 204:
        print(f"Permissions set for user '{username}' on vhost '{vhost}'.")
    else:
        print(f"Failed to set permissions for user '{username}' on vhost '{vhost}': {response.content}")

# Example usage
if __name__ == "__main__":
    vhosts = ['app1_vhost', 'app2_vhost']
    users = {'app1_user': 'password1', 'app2_user': 'password2'}

    for vhost in vhosts:
        create_vhost(vhost)

